it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
  // ##./#.. → ##./##. — (1,1) is born; all three live cells survive
  const result = nextGeneration([
    [0, 0],
    [1, 0],
    [0, 1],
  ]);
  expect(result.sort()).toEqual(
    [
      [0, 0],
      [1, 0],
      [0, 1],
      [1, 1],
    ].sort(),
  );
});
